// prefixed columns are all NULL yields nil (no child), and NULL values never
// error, they just leave the zero value in the field.
func teamScanMapperNullable(prefix string) scan.Mapper[*Team] {
	return func(ctx context.Context, cols []string) (scan.BeforeFunc, func(any) (*Team, error)) {
		// resolve the column names once per query, not per row
		type target struct {
			idx int
			dst func(b *teamPreloadBuf) any
		}
		targets := make([]target, 0, 3)
		for i, col := range cols {
			name, ok := strings.CutPrefix(col, prefix)
			if !ok {
				continue
			}
			switch name {
			case "id":
				targets = append(targets, target{i, func(b *teamPreloadBuf) any { return &b.ID }})
			case "name":
				targets = append(targets, target{i, func(b *teamPreloadBuf) any { return &b.Name }})
			case "created_at":
				targets = append(targets, target{i, func(b *teamPreloadBuf) any { return &b.CreatedAt }})
			}
		}

		// One scratch buffer reused for every row: before -> scan -> after runs
		// synchronously per row, the scheduled columns are fully overwritten each
		// row, and unselected columns stay zero, so a single buffer preserves the
		// per-row NULL semantics without allocating a buffer per parent row. The
		// returned child (o below) is always freshly allocated, so buf never
		// escapes past the after func.
		buf := new(teamPreloadBuf)
		return func(row *scan.Row) (any, error) {
				for _, t := range targets {
					row.ScheduleScanByIndex(t.idx, t.dst(buf))
				}
				return buf, nil
			}, func(link any) (*Team, error) {
				buf := link.(*teamPreloadBuf)

				// Same rule as the reflection mapper's row validator: the child
				// exists only if at least one of its columns is not NULL. Columns
				// not selected by the query are never scanned and stay invalid,
				// so this check also matches when only a subset is selected.
				if !(buf.ID.Valid) &&
					!(buf.Name.Valid) &&
					!(buf.CreatedAt.Valid) {
					return nil, nil
				}

				o := new(Team)
				if buf.ID.Valid {
					o.ID = buf.ID.V
				}
				if buf.Name.Valid {
					o.Name = buf.Name.V
				}
				if buf.CreatedAt.Valid {
					o.CreatedAt = buf.CreatedAt.V
				}
				return o, nil
			}
	}
}

func (o *Team) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "TeamGithubAccounts":
		rels, ok := retrieved.(TeamGithubAccountSlice)
		if !ok {
			return fmt.Errorf("team cannot load %T as %q", retrieved, name)
		}

		o.R.TeamGithubAccounts = rels
		o.R.Loaded.TeamGithubAccounts = true

		for _, rel := range rels {
			if rel != nil {
				rel.R.Team = o
				rel.R.Loaded.Team = true
			}
		}
		return nil
	case "Users":
		rels, ok := retrieved.(UserSlice)
		if !ok {
			return fmt.Errorf("team cannot load %T as %q", retrieved, name)
		}

		o.R.Users = rels
		o.R.Loaded.Users = true

		for _, rel := range rels {
			if rel != nil {
				rel.R.Team = o
				rel.R.Loaded.Team = true
			}
		}
		return nil
	default:
		return fmt.Errorf("team has no relationship %q", name)
	}
}

type teamPreloader struct{}

func buildTeamPreloader() teamPreloader {
	return teamPreloader{}
}

type teamThenLoader[Q orm.Loadable] struct {
	TeamGithubAccounts func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	Users              func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
}

func buildTeamThenLoader[Q orm.Loadable]() teamThenLoader[Q] {
	type TeamGithubAccountsLoadInterface interface {
		LoadTeamGithubAccounts(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type UsersLoadInterface interface {
		LoadUsers(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}

	return teamThenLoader[Q]{
		TeamGithubAccounts: thenLoadBuilder[Q](
			"TeamGithubAccounts",
			func(ctx context.Context, exec bob.Executor, retrieved TeamGithubAccountsLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadTeamGithubAccounts(ctx, exec, mods...)
			},
		),
		Users: thenLoadBuilder[Q](
			"Users",
			func(ctx context.Context, exec bob.Executor, retrieved UsersLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadUsers(ctx, exec, mods...)
			},
		),
	}
}

// LoadTeamGithubAccounts loads the team's TeamGithubAccounts into the .R struct
func (o *Team) LoadTeamGithubAccounts(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.TeamGithubAccounts = nil
	o.R.Loaded.TeamGithubAccounts = false

	related, err := o.TeamGithubAccounts(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, rel := range related {
		rel.R.Team = o
		rel.R.Loaded.Team = true
	}

	o.R.TeamGithubAccounts = related
	o.R.Loaded.TeamGithubAccounts = true
	return nil
}

// LoadTeamGithubAccounts loads the team's TeamGithubAccounts into the .R struct
func (os TeamSlice) LoadTeamGithubAccounts(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	teamGithubAccounts, err := os.TeamGithubAccounts(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.TeamGithubAccounts = nil
		o.R.Loaded.TeamGithubAccounts = true
	}
	// O(N+M) stitch via a map keyed by the join column (key -> []parent; was O(N*M)).
	teamByKey := make(map[string][]*Team, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}

		teamByKey[o.ID] = append(teamByKey[o.ID], o)
	}

	for _, rel := range teamGithubAccounts {

		owners, ok := teamByKey[rel.TeamID]
		if !ok {
			continue
		}

		for _, o := range owners {

			rel.R.Team = o
			rel.R.Loaded.Team = true

			o.R.TeamGithubAccounts = append(o.R.TeamGithubAccounts, rel)

		}
	}

	return nil
}

// LoadUsers loads the team's Users into the .R struct
func (o *Team) LoadUsers(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Users = nil
	o.R.Loaded.Users = false

	related, err := o.Users(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, rel := range related {
		rel.R.Team = o
		rel.R.Loaded.Team = true
	}

	o.R.Users = related
	o.R.Loaded.Users = true
	return nil
}

// LoadUsers loads the team's Users into the .R struct
func (os TeamSlice) LoadUsers(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	users, err := os.Users(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.Users = nil
		o.R.Loaded.Users = true
	}
	// O(N+M) stitch via a map keyed by the join column (key -> []parent; was O(N*M)).
	teamByKey := make(map[string][]*Team, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}

		teamByKey[o.ID] = append(teamByKey[o.ID], o)
	}

	for _, rel := range users {

		if !rel.TeamID.Valid {
			continue
		}

		owners, ok := teamByKey[rel.TeamID.V]
		if !ok {
			continue
		}

		for _, o := range owners {

			rel.R.Team = o
			rel.R.Loaded.Team = true

			o.R.Users = append(o.R.Users, rel)

		}
	}

	return nil
}

// teamC is where relationship counts are stored.
type teamC struct {
	TeamGithubAccounts *int64
	Users              *int64
}

// PreloadCount sets a count in the C struct by name
func (o *Team) PreloadCount(name string, count int64) error {
	if o == nil {
		return nil
	}

	switch name {
	case "TeamGithubAccounts":
		o.C.TeamGithubAccounts = &count
	case "Users":
		o.C.Users = &count
	}
	return nil
}

type teamCountPreloader struct {
	TeamGithubAccounts func(...bob.Mod[*dialect.SelectQuery]) mysql.Preloader
	Users              func(...bob.Mod[*dialect.SelectQuery]) mysql.Preloader
}

func buildTeamCountPreloader() teamCountPreloader {
	return teamCountPreloader{
		TeamGithubAccounts: func(mods ...bob.Mod[*dialect.SelectQuery]) mysql.Preloader {
			return countPreloader[*Team]("TeamGithubAccounts", func(parent string) bob.Expression {
				// Build a correlated subquery: (SELECT COUNT(*) FROM related WHERE fk = parent.pk)
				if parent == "" {
					parent = Teams.Alias()
				}

				subqueryMods := []bob.Mod[*dialect.SelectQuery]{
					sm.Columns(mysql.Raw("count(*)")),

					sm.From(TeamGithubAccounts.NameAsExpr()),
					sm.Where(mysql.Quote(TeamGithubAccounts.Alias(), "team_id").EQ(mysql.Quote(parent, "id"))),
				}
				subqueryMods = append(subqueryMods, mods...)
				return mysql.Group(mysql.Select(subqueryMods...).Expression)
			})
		},
		Users: func(mods ...bob.Mod[*dialect.SelectQuery]) mysql.Preloader {
			return countPreloader[*Team]("Users", func(parent string) bob.Expression {
				// Build a correlated subquery: (SELECT COUNT(*) FROM related WHERE fk = parent.pk)
				if parent == "" {
					parent = Teams.Alias()
				}

				subqueryMods := []bob.Mod[*dialect.SelectQuery]{
					sm.Columns(mysql.Raw("count(*)")),

					sm.From(Users.NameAsExpr()),
					sm.Where(mysql.Quote(Users.Alias(), "team_id").EQ(mysql.Quote(parent, "id"))),
				}
				subqueryMods = append(subqueryMods, mods...)
				return mysql.Group(mysql.Select(subqueryMods...).Expression)
			})
		},
	}
}

