// LoadCountTeamGithubAccounts loads the count of TeamGithubAccounts for a slice in a single batch query
func (os TeamSlice) LoadCountTeamGithubAccounts(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	// Build the IN arg expression from parent PKs
	PKArgSlice := make([]bob.Expression, 0, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}
		PKArgSlice = append(PKArgSlice, mysql.Arg(o.ID))
	}
	PKArgExpr := mysql.Group(PKArgSlice...)

	// countResult holds one scanned row from the batch count query.
	// FK columns are aliased to the parent PK column names for direct map lookup.
	type countResult struct {
		ID    string
		Count int64
	}

	batchMods := []bob.Mod[*dialect.SelectQuery]{
		// SELECT fk AS parent_pk, count(*)
		sm.Columns(
			TeamGithubAccounts.Columns.TeamID.As("id"),
			mysql.Raw("count(*) as count"),
		),
		// Single-hop: FROM related table directly
		sm.From(TeamGithubAccounts.NameAsExpr()),

		// WHERE fk IN (parent PKs) — psql single-column FK uses `= ANY(array)` (see PKArgExpr above)
		sm.Where(TeamGithubAccounts.Columns.TeamID.OP("IN", PKArgExpr)),
		// GROUP BY fk columns
		sm.GroupBy(TeamGithubAccounts.Columns.TeamID),
	}
	batchMods = append(batchMods, mods...)

	results, err := bob.All(ctx, exec,
		mysql.Select(batchMods...),
		scan.StructMapper[countResult](),
	)
	if err != nil {
		return err
	}

	// Single-column FK: direct map lookup
	countMap := make(map[string]int64, len(results))
	for _, r := range results {
		countMap[r.ID] = r.Count
	}
	for _, o := range os {
		if o == nil {
			continue
		}
		count := countMap[o.ID]
		o.C.TeamGithubAccounts = &count
	}

	return nil
}

